select temp.*,
from (select
,
,rdt.id as rdt_id, rdt.demand_id as rdt_demand_id, rdt.re_content as rdt_re_content, rdt.update_time as rdt_update_time, rdt.edit_by as rdt_edit_by, rdan.id as rdan_id, rdan.jobName as rdan_jobName, rdan.agree_num as rdan_agree_num, rdan.job_second_count as rdan_job_second_count, rdan.job_third_count as rdan_job_third_count, rdan.job_current_count as rdan_job_current_count, rdan.create_time as rdan_create_time, rdan.demand_id as rdan_demand_id, rdan.edit_by as rdan_edit_by
,(select top 1 job_class from fnd_job fd where fd.id = rdj.job_id and fd.enabled_flag = 1 and fd.deleted_flag = 0 ) as rdj_job_class FROM re_demand rd LEFT JOIN re_demand_job rdj ON rd.id = rdj.demand_id and rdj.enabled_flag =1 LEFT JOIN re_demand_tracking rdt on rd.id = rdt.demand_id and rdt.enabled_flag = 1 LEFT JOIN re_demand_agree_num rdan ON rd.id = rdan.demand_id and rdan.agree_num is not null WHERE rd.enabled_flag = 1
and rd.oa_order = #{criteria.oaOrder, jdbcType = VARCHAR}
and rd.id = #{criteria.id, jdbcType = BIGINT}
) temp left join re_demand_job_describes rdjd on rdjd.demand_job_id = temp.rdj_id and rdjd.enabled_flag = 1


select case when exists (
    select 1 from re_demand rd join re_demand_job rdj on rd.id = rdj.demand_id
        and rd.enabled_flag = 1 and rdj.enabled_flag = 1
        and isnull(rdj.pass_quantity, 0) < rdj.quantity
        and rd.id = #{id, jdbcType = BIGINT}
) then 1 else 0 end

